typedef enum
{
  ENGINE_KEYMOD_NONE   = SDL_KMOD_NONE,
  ENGINE_KEYMOD_LSHIFT = SDL_KMOD_LSHIFT,
  ENGINE_KEYMOD_RSHIFT = SDL_KMOD_RSHIFT,
  ENGINE_KEYMOD_LEVEL5 = SDL_KMOD_LEVEL5,
  ENGINE_KEYMOD_LCTRL  = SDL_KMOD_LCTRL,
  ENGINE_KEYMOD_RCTRL  = SDL_KMOD_RCTRL,
  ENGINE_KEYMOD_LALT   = SDL_KMOD_LALT,
  ENGINE_KEYMOD_RALT   = SDL_KMOD_RALT,
  ENGINE_KEYMOD_LGUI   = SDL_KMOD_LGUI,
  ENGINE_KEYMOD_RGUI   = SDL_KMOD_RGUI,
  ENGINE_KEYMOD_NUM    = SDL_KMOD_NUM,
  ENGINE_KEYMOD_CAPS   = SDL_KMOD_CAPS,
  ENGINE_KEYMOD_MODE   = SDL_KMOD_MODE,
  ENGINE_KEYMOD_SCROLL = SDL_KMOD_SCROLL,
  ENGINE_KEYMOD_CTRL   = SDL_KMOD_CTRL,
  ENGINE_KEYMOD_SHIFT  = SDL_KMOD_SHIFT,
  ENGINE_KEYMOD_ALT    = SDL_KMOD_ALT,
  ENGINE_KEYMOD_GUI    = SDL_KMOD_GUI,
} engine_keymode_e;

// Internal API
// -----------------------------------------------------------------

void engine_keyboard_setup(void);
void engine_keyboard_update(void); // Should be called once per frame just
                                   // before processing input events
void engine_keyboard_shutdown(void);
void engine_key_up(engine_key_e scancode);
void engine_key_down(engine_key_e scancode);

// Public API
// -----------------------------------------------------------------

const char *engine_key_name(engine_key_e key); // Use the current modifier state
                                               // to determine the key name
const char *engine_key_name_ex(engine_key_e key, engine_keymode_e mod);

bool engine_key_pressed(engine_key_e key);
bool engine_key_released(engine_key_e key);

bool engine_key_just_pressed(engine_key_e key);
bool engine_key_just_released(engine_key_e key);

Uint64 engine_key_held_time(engine_key_e key);

bool engine_keymod_pressed(engine_keymode_e mod);

#endif // ENGINE_KEYBOARD_H_
